    /// <summary>
    /// Logs only non-sensitive headers. Sensitive headers are logged as "[REDACTED]".
    /// </summary>
    private static void LogSafeHeaders(HttpRequest req, string correlationId, ILogger log)
    {
        var safeHeaders = new Dictionary<string, string>();

        foreach (var header in req.Headers)
        {
            if (SensitiveHeaders.Contains(header.Key))
            {
                safeHeaders[header.Key] = "[REDACTED]";
            }
            else
            {
                safeHeaders[header.Key] = header.Value.ToString();
            }
        }

        log.LogDebug("CorrelationId={CorrelationId} | Headers={Headers}",
            correlationId, JsonConvert.SerializeObject(safeHeaders));
    }

    /// <summary>
    /// Reads the request body and logs a sanitized version with sensitive fields redacted.
    /// </summary>
    private static async Task<string> ReadAndLogSanitizedBody(HttpRequest req, string correlationId, ILogger log)
    {
        req.EnableBuffering();
        using var reader = new StreamReader(req.Body, leaveOpen: true);
        string requestBody = await reader.ReadToEndAsync();
        req.Body.Position = 0;

        if (!string.IsNullOrWhiteSpace(requestBody))
        {
            string sanitizedBody = SanitizeJsonBody(requestBody);

            // Truncate very large bodies to prevent log flooding
            const int maxLogLength = 4096;
            if (sanitizedBody.Length > maxLogLength)
            {
                sanitizedBody = sanitizedBody[..maxLogLength] + "...[TRUNCATED]";
            }

            log.LogDebug("CorrelationId={CorrelationId} | RequestBody={Body}",
                correlationId, sanitizedBody);
        }

        return requestBody;
    }

    /// <summary>
    /// Redacts sensitive fields from a JSON body string.
    /// </summary>
    private static string SanitizeJsonBody(string jsonBody)
    {
        try
        {
            var obj = JsonConvert.DeserializeObject<Dictionary<string, object>>(jsonBody);
            if (obj == null) return jsonBody;

            var sanitized = new Dictionary<string, object>();
            foreach (var kvp in obj)
            {
                if (SensitiveBodyFields.Contains(kvp.Key))
                {
                    sanitized[kvp.Key] = "[REDACTED]";
                }
                else
                {
                    sanitized[kvp.Key] = kvp.Value;
                }
            }

            return JsonConvert.SerializeObject(sanitized);
        }
        catch (JsonException)
        {
            // Not valid JSON; return a placeholder rather than raw content that might be sensitive
            return "[NON-JSON BODY - NOT LOGGED]";
        }
    }

    /// <summary>
    /// Extracts safe, non-sensitive user context (e.g., user ID, roles) without tokens.
    /// </summary>
    private static Dictionary<string, string> ExtractSafeUserContext(HttpRequest req, string correlationId, ILogger log)
    {
        var context = new Dictionary<string, string>();

        // Extract user identity from the claims principal (set by Azure AD / EasyAuth)
        // This does NOT log the raw token—only the derived claims.
        if (req.HttpContext.User?.Identity?.IsAuthenticated == true)
        {
            var claims = req.HttpContext.User.Claims.ToList();

            // Only log non-sensitive claim types
            var safeClaims = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
            {
                "sub",
                "oid",           // Azure AD object ID
                "preferred_username",
                "name",
                "roles"
            };

            foreach (var claim in claims)
            {
                var shortType = claim.Type.Split('/').Last();
                if (safeClaims.Contains(shortType))
                {
                    context[shortType] = claim.Value;
                }
            }

            log.LogInformation("CorrelationId={CorrelationId} | AuthenticatedUser={UserContext}",
                correlationId, JsonConvert.SerializeObject(context));
        }
        else
        {
            log.LogInformation("CorrelationId={CorrelationId} | User is not authenticated", correlationId);
        }

        return context;
    }

    /// <summary>
    /// Handles user queries using parameterized SQL to prevent injection.
    /// Logs query metadata without exposing sensitive parameter values.
