    private static async Task<object> HandleUserQuery(
        string requestBody, Dictionary<string, string> userContext, string correlationId, ILogger log)
    {
        var request = JsonConvert.DeserializeObject<Dictionary<string, string>>(requestBody ?? "{}");
        string userId = request?.GetValueOrDefault("userId");

        if (string.IsNullOrWhiteSpace(userId))
            throw new ArgumentException("userId is required");

        // Use parameterized queries — never concatenate user input into SQL
        const string query = "SELECT Id, DisplayName, Email, CreatedDate FROM Users WHERE Id = @UserId AND IsActive = 1";

        // Log the query template and parameter names (not values that might be PII)
        log.LogDebug("CorrelationId={CorrelationId} | Executing query={Query} | ParameterNames={Params}",
            correlationId, query, "[@UserId]");

        var connectionString = Environment.GetEnvironmentVariable("SqlConnectionString");
        if (string.IsNullOrEmpty(connectionString))
            throw new InvalidOperationException("Database connection string is not configured");

        var results = new List<Dictionary<string, object>>();

        using (var connection = new SqlConnection(connectionString))
        {
            await connection.OpenAsync();
            using var command = new SqlCommand(query, connection);
            command.Parameters.AddWithValue("@UserId", userId);
            command.CommandTimeout = 30;

            using var reader = await command.ExecuteReaderAsync();
            while (await reader.ReadAsync())
            {
                results.Add(new Dictionary<string, object>
