                    ["id"] = reader["Id"],
                    ["displayName"] = reader["DisplayName"],
                    // Note: Email is PII; in production you might redact or omit this from logs
                    ["createdDate"] = reader["CreatedDate"]
                });
            }
        }

        log.LogInformation("CorrelationId={CorrelationId} | UserQuery returned {Count} results", correlationId, results.Count);

        return results;
    }

    /// <summary>
    /// Handles order queries using parameterized SQL.
    /// </summary>
    private static async Task<object> HandleOrderQuery(
        string requestBody, Dictionary<string, string> userContext, string correlationId, ILogger log)
    {
        var request = JsonConvert.DeserializeObject<Dictionary<string, string>>(requestBody ?? "{}");
        string orderId = request?.GetValueOrDefault("orderId");
        string status = request?.GetValueOrDefault("status");

        const string query = @"
            SELECT o.Id, o.Status, o.TotalAmount, o.CreatedDate 
            FROM Orders o 
            WHERE (@OrderId IS NULL OR o.Id = @OrderId) 
              AND (@Status IS NULL OR o.Status = @Status)
            ORDER BY o.CreatedDate DESC
            OFFSET 0 ROWS FETCH NEXT 50 ROWS ONLY";

        log.LogDebug("CorrelationId={CorrelationId} | Executing order query | ParameterNames={Params}",
            correlationId, "[@OrderId, @Status]");

        var connectionString = Environment.GetEnvironmentVariable("SqlConnectionString");
        if (string.IsNullOrEmpty(connectionString))
            throw new InvalidOperationException("Database connection string is not configured");

        var results = new List<Dictionary<string, object>>();

        using (var connection = new SqlConnection(connectionString))
        {
            await connection.OpenAsync();
            using var command = new SqlCommand(query, connection);
            command.Parameters.AddWithValue("@OrderId", (object)orderId ?? DBNull.Value);
            command.Parameters.AddWithValue("@Status", (object)status ?? DBNull.Value);
            command.CommandTimeout = 30;

            using var reader = await command.ExecuteReaderAsync();
            while (await reader.ReadAsync())
            {
                results.Add(new Dictionary<string, object>
                {
                    ["id"] = reader["Id"],
                    ["status"] = reader["Status"],
                    ["totalAmount"] = reader["TotalAmount"],
                    ["createdDate"] = reader["CreatedDate"]
                });
            }
        }

        log.LogInformation("CorrelationId={CorrelationId} | OrderQuery returned {Count} results", correlationId, results.Count);

        return results;
    }

    private static object HandleHealthCheck(string correlationId, ILogger log)
