    /// <summary>
    /// Removes potential sensitive data from exception messages (e.g., connection strings, credentials).
    /// </summary>
    private static string SanitizeExceptionMessage(string message)
    {
        if (string.IsNullOrEmpty(message)) return message;

        // Remove anything that looks like a connection string
        message = System.Text.RegularExpressions.Regex.Replace(
            message,
            @"(Server|Data Source|Initial Catalog|User Id|Password|Integrated Security|Trusted_Connection)\s*=\s*[^;""]+",
            "$1=[REDACTED]",
            System.Text.RegularExpressions.RegexOptions.IgnoreCase);

        // Remove anything that looks like a bearer token
        message = System.Text.RegularExpressions.Regex.Replace(
            message,
            @"Bearer\s+[A-Za-z0-9\-._~+/]+=*",
            "Bearer [REDACTED]",
            System.Text.RegularExpressions.RegexOptions.IgnoreCase);

        return message;
    }
